sys_script.script:
(function executeRule(current, previous) {
    // Validate Units Available >= 0
    var units = parseInt(current.getValue('units_available'));
    if (isNaN(units) || units < 0) {
        gs.addErrorMessage('Units Available must be a non-negative number.');
        current.setAbortAction(true);
        return;
    }

    // Validate Expiry Date >= Today
    var expiryDate = current.getValue('expiry_date');
    if (expiryDate) {
        var today = new GlideDateTime();
        var expiry = new GlideDateTime(expiryDate);
        if (expiry.compareTo(today) < 0) {
            gs.addErrorMessage('Expiry Date must be today or in the future.');
            current.setAbortAction(true);
            return;
        }
    }
})(current, previous);
